LXImport("..Struct.StructTemplate")

local LModel = LModel
------------------------------------------------------------------
---@class ModelTemplate:LModel
local ModelTemplate = LxClass("ModelTemplate",LModel)
------------------------------------------------------------------
function ModelTemplate:ModelTemplate()
	self._templateData = nil
	self._timer = nil
end

--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelTemplate:OnModelInit()

end

--在协议数据处理完之后需要调用finish
function ModelTemplate:OnModelRequest()
	self._timer = LxTimer.DelayTimeCall(function() self:OnTestDelayFinish() end, 1)
end

function ModelTemplate:OnTestDelayFinish()
	--test pb dataList
	local testPb = {
		{id =1,name="test1",temp="abc",temp2="cdef"},
		{id =2,name="test2",temp="abc",temp2="cdef"},
		{id =3,name="test3",temp="abc",temp2="cdef"},
		{id =4,name="test4",temp="abc",temp2="cdef"}
	}
	local dataList = {}
	for k,pb in ipairs(testPb) do
		local data = StructTemplate:New()
		data:CreateByPb(pb)
		dataList[pb.id] = data
	end
	self._templateData = dataList

	self:ModelFinish()
end

--清理工作
--停止计时器之类的
function ModelTemplate:OnModelClear()
	local timer = self._timer
	if timer then
		LxTimer.DelayTimeStop(timer)
		self._timer = nil
	end
end

return ModelTemplate